mapper.select:
SELECT combined.recordType AS recordType, combined.id AS id, combined.title AS title, combined.status AS status, combined.contractType AS contractType, combined.monthlySupplyKwh AS monthlySupplyKwh, combined.startDate AS startDate, combined.endDate AS endDate, combined.quantity AS quantity, combined.kwhEquivalent AS kwhEquivalent, combined.completedDate AS completedDate, combined.totalAmount AS totalAmount, combined.supplyType AS supplyType, combined.eventDate AS eventDate, combined.createdBy AS createdBy FROM ( SELECT 'CONTRACT' AS recordType, c.id AS id, c.supplier_name AS title, c.status AS status, c.contract_type AS contractType, c.monthly_supply_kwh AS monthlySupplyKwh, c.start_date AS startDate, c.end_date AS endDate, NULL AS quantity, NULL AS kwhEquivalent, NULL AS completedDate, NULL AS totalAmount, NULL AS supplyType, c.created_at AS eventDate, c.created_by AS createdBy FROM contracts c WHERE c.is_deleted = 0
AND c.status = #{status}
AND c.created_at >= #{startDate}
AND c.created_at <= #{endDate}
UNION ALL
SELECT 'PROCUREMENT' AS recordType, p.id AS id, p.supplier_name AS title, p.status AS status, NULL AS contractType, NULL AS monthlySupplyKwh, NULL AS startDate, p.completed_date AS endDate, p.quantity AS quantity, p.kwh_equivalent AS kwhEquivalent, p.completed_date AS completedDate, p.total_amount AS totalAmount, p.supply_type AS supplyType, COALESCE(p.completed_date, p.created_at) AS eventDate, p.created_by AS createdBy FROM procurements p WHERE p.is_deleted = 0
AND p.status = #{status}
AND p.supply_type = #{supplyType}
AND COALESCE(p.completed_date, p.created_at) >= #{startDate}
AND COALESCE(p.completed_date, p.created_at) <= #{endDate}
) AS combined
combined.recordType = 'CONTRACT'
combined.recordType = 'PROCUREMENT'
ORDER BY combined.eventDate DESC
